class Solution(object):
    def getAllElements(self, root1, root2):
        def inorder(node, result):
            if not node:
                return
            inorder(node.left, result)
            result.append(node.val)
            inorder(node.right, result)
        list1 = []
        list2 = []
        inorder(root1, list1)
        inorder(root2, list2)
        return sorted(list1 + list2)
